1	type Item = { type: string; enchantment?: number };
2	type Scenario = {
3	  steps: Array<{ op: string; items?: Item[] }>;
4	};
5	
6	const PROCESSING_FEE = 5;
7	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	  rune: 25,
13	  moonstone: 25,
14	};
15	const BLOCK_OF_3_PRICE = 60;
16	const BLOCK_ELIGIBLE_TYPES = new Set(["rune", "moonstone"]);
17	const HIGH_ENCHANTMENT_THRESHOLD = 5;
18	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
19	
20	function quotePremium(items: Item[]): number {
21	  const countsByType: Record<string, number> = {};
22	  for (const item of items) {
23	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
24	  }
25	  let policyBase = 0;
26	  for (const [type, count] of Object.entries(countsByType)) {
27	    if (BLOCK_ELIGIBLE_TYPES.has(type) && count === 3) {
28	      policyBase += BLOCK_OF_3_PRICE;
29	    } else {
30	      policyBase += count * BASE_PREMIUM_BY_ITEM_TYPE[type];
31	    }
32	  }
33	  let itemSurcharges = 0;
34	  for (const item of items) {
35	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
36	      itemSurcharges +=
37	        HIGH_ENCHANTMENT_SURCHARGE_RATE * BASE_PREMIUM_BY_ITEM_TYPE[item.type];
38	    }
39	  }
40	  const firstInsurance = policyBase / 10;
41	  return Math.ceil(policyBase + itemSurcharges + firstInsurance) + PROCESSING_FEE;
42	}
43	
44	export function processScenario(scenario: unknown): unknown {
45	  const { steps } = scenario as Scenario;
46	  const results = steps.map((step) => ({
47	    premium: quotePremium(step.items ?? []),
48	  }));
49	  return { results };
50	}
